29	const groupByType = (items: Item[]): Item[][] => {
30	  const groups: Record<string, Item[]> = {};
31	  for (const item of items) {
32	    (groups[item.type] ||= []).push(item);
33	  }
34	  return Object.values(groups);
35	};
36	
37	const groupBasePremium = (group: Item[]): number =>
38	  isBlockOfThreeAlike(group)
39	    ? BLOCK_OF_THREE_BASE_PREMIUM
40	    : sum(group.map(itemBasePremium));
41	
42	const itemsBasePremium = (items: Item[]): number =>
43	  sum(groupByType(items).map(groupBasePremium));
44	
45	const cursedSurcharge = (item: Item): number =>
46	  item.cursed ? itemBasePremium(item) * CURSED_SURCHARGE_RATE : 0;
47	
48	const itemSurchargesTotal = (items: Item[]): number =>
49	  sum(items.map(cursedSurcharge));
50	
51	const applyFirstInsuranceSurcharge = (amount: number): number =>
52	  amount + amount * FIRST_INSURANCE_SURCHARGE_RATE;
53	
54	const quotePremiumFor = (items: Item[]): number =>
55	  Math.ceil(
56	    applyFirstInsuranceSurcharge(itemsBasePremium(items)) +
57	      itemSurchargesTotal(items) +
58	      PROCESSING_FEE,
59	  );
60	
61	export const runScenario = (input: Scenario): unknown =>
62	  quoteResult(quotePremiumFor(input.steps[0].items));
